import{_ as e,c as o,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"詳細な設定と最適化 | opencode-notifyチュートリアル","description":"opencode-notifyの高度な設定を学習：設定リファレンス、サイレント時間、ターミナル検出、ベストプラクティス。個々のニーズに応じて通知体験を最適化し、生産性を向上させます。","frontmatter":{"title":"詳細な設定と最適化 | opencode-notifyチュートリアル","sidebarTitle":"通知体験のカスタマイズ","subtitle":"詳細な設定と最適化","description":"opencode-notifyの高度な設定を学習：設定リファレンス、サイレント時間、ターミナル検出、ベストプラクティス。個々のニーズに応じて通知体験を最適化し、生産性を向上させます。","tags":["高度な設定","設定","最適化"],"prerequisite":["start-quick-start","start-how-it-works"],"order":3},"headers":[],"relativePath":"ja/kdcokenny/opencode-notify/advanced/index.md","filePath":"ja/kdcokenny/opencode-notify/advanced/index.md"}'),i={name:"ja/kdcokenny/opencode-notify/advanced/index.md"};function n(l,t,d,c,s,h){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="詳細な設定と最適化" tabindex="-1">詳細な設定と最適化 <a class="header-anchor" href="#詳細な設定と最適化" aria-label="Permalink to &quot;詳細な設定と最適化&quot;">​</a></h1><p>本章ではopencode-notifyの高度な機能を習得し、設定オプションを深く理解し、通知体験を最適化し、個々のニーズに応じて通知動作をカスタマイズする方法を学びます。</p><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><p>本章の内容は以下の順序で学習することを推奨します：</p><h3 id="_1-設定リファレンス" tabindex="-1">1. <a href="./config-reference/">設定リファレンス</a> <a class="header-anchor" href="#_1-設定リファレンス" aria-label="Permalink to &quot;1. [設定リファレンス](./config-reference/)&quot;">​</a></h3><p>すべての利用可能な設定オプションとその機能を包括的に理解します。</p><ul><li>設定ファイルの構造と構文の習得</li><li>通知音のカスタマイズ方法の学習</li><li>サブセッション通知スイッチの使用シナリオの理解</li><li>ターミナルタイプオーバーライドの設定方法の学習</li></ul><h3 id="_2-サイレント時間の詳細" tabindex="-1">2. <a href="./quiet-hours/">サイレント時間の詳細</a> <a class="header-anchor" href="#_2-サイレント時間の詳細" aria-label="Permalink to &quot;2. [サイレント時間の詳細](./quiet-hours/)&quot;">​</a></h3><p>特定の時間に邪魔されないよう、サイレント時間を設定する方法を学びます。</p><ul><li>サイレント時間の開始・終了時間の設定</li><li>夜間のサイレント時間の処理（例：22:00 - 08:00）</li><li>必要に応じてサイレント機能を一時的に無効化</li><li>サイレント時間と他のフィルタリングルールの優先順位の理解</li></ul><h3 id="_3-ターミナル検出の原理" tabindex="-1">3. <a href="./terminal-detection/">ターミナル検出の原理</a> <a class="header-anchor" href="#_3-ターミナル検出の原理" aria-label="Permalink to &quot;3. [ターミナル検出の原理](./terminal-detection/)&quot;">​</a></h3><p>ターミナルの自動検出メカニズムについて深く理解します。</p><ul><li>プラグインが37+のターミナルエミュレータを識別する方法の学習</li><li>macOSプラットフォームのフォーカス検出実装の理解</li><li>ターミナルタイプを手動で指定する方法の習得</li><li>検出失敗時のデフォルト動作の理解</li></ul><h3 id="_4-高度な使用方法" tabindex="-1">4. <a href="./advanced-usage/">高度な使用方法</a> <a class="header-anchor" href="#_4-高度な使用方法" aria-label="Permalink to &quot;4. [高度な使用方法](./advanced-usage/)&quot;">​</a></h3><p>設定テクニックとベストプラクティスを習得します。</p><ul><li>通知スパムを回避する設定戦略</li><li>ワークフローに応じた通知動作の調整</li><li>マルチウィンドウ・マルチターミナル環境での設定推奨事項</li><li>パフォーマンス最適化とトラブルシューティングのテクニック</li></ul><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>本章の学習を開始する前に、以下の基礎内容を完了することを推奨します：</p><ul><li>✅ <strong>クイックスタート</strong>：プラグインのインストールと基本設定の完了</li><li>✅ <strong>動作原理</strong>：プラグインのコア機能とイベントリスニングメカニズムの理解</li><li>✅ <strong>プラットフォーム特性</strong>（オプション）：使用しているプラットフォームの特定機能の理解</li></ul><div class="tip custom-block"><p class="custom-block-title">学習のヒント</p><p>通知音のカスタマイズやサイレント時間の設定のみを行いたい場合は、直接対応するサブページにジャンプできます。問題が発生した場合は、いつでも設定リファレンスの章を参照してください。</p></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>本章の学習を完了した後、以下の内容を引き続き探索できます：</p><ul><li><strong><a href="./../../faq/troubleshooting/">トラブルシューティング</a></strong>：一般的な問題と難解な問題の解決</li><li><strong><a href="./../../faq/common-questions/">よくある質問</a></strong>：ユーザーが関心を持つホットトピックの理解</li><li><strong><a href="./../../appendix/event-types/">イベントタイプの説明</a></strong>：プラグインがリッスンするすべてのイベントタイプの深い学習</li><li><strong><a href="./../../appendix/config-file-example/">設定ファイルの例</a></strong>：完全な設定例とコメントの確認</li></ul><hr><details><summary><strong>ソースコードの場所を表示</strong></summary><blockquote><p>最終更新：2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>設定インターフェース定義</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L30-L48" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>30-48</td></tr><tr><td>デフォルト設定</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L56-L68" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>56-68</td></tr><tr><td>設定の読み込み</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L90-L114" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>90-114</td></tr><tr><td>サイレント時間のチェック</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L181-L199" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>181-199</td></tr><tr><td>ターミナル検出</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L145-L176" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>145-176</td></tr><tr><td>ターミナルプロセス名マッピング</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L71-L84" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>71-84</td></tr></tbody></table><p><strong>重要なインターフェース</strong>：</p><ul><li><code>NotifyConfig</code>：設定インターフェース、すべての設定項目を含む</li><li><code>quietHours</code>：サイレント時間設定（enabled/start/end）</li><li><code>sounds</code>：サウンド設定（idle/error/permission）</li><li><code>terminal</code>：ターミナルタイプのオーバーライド（オプション）</li></ul><p><strong>重要な定数</strong>：</p><ul><li><code>DEFAULT_CONFIG</code>：すべての設定項目のデフォルト値</li><li><code>TERMINAL_PROCESS_NAMES</code>：ターミナル名からmacOSプロセス名へのマッピングテーブル</li></ul></details>',25)])])}const u=e(i,[["render",n]]);export{p as __pageData,u as default};
